package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.account.*;import com.chaobo.scm.supplier.application.shared.CommandResult;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.*;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api/supplier/v1/access")public class SupplierAccessController{private final SupplierAccessApplicationService service;private final CommandContextFactory contexts;public SupplierAccessController(SupplierAccessApplicationService service,CommandContextFactory contexts){this.service=service;this.contexts=contexts;}@GetMapping("/suppliers/{supplierId}/contacts")public ApiResponse<List<SupplierContactView>> contacts(@PathVariable long supplierId,HttpServletRequest request,Authentication authentication){return ok(service.contacts(supplierId,contexts.create(request,authentication)),request);}@GetMapping("/contacts/{id}")public ApiResponse<SupplierContactView> contact(@PathVariable long id,HttpServletRequest request,Authentication authentication){return ok(service.contact(id,contexts.create(request,authentication)),request);}@GetMapping("/suppliers/{supplierId}/users")public ApiResponse<List<SupplierUserBindingView>> bindings(@PathVariable long supplierId,HttpServletRequest request,Authentication authentication){return ok(service.bindings(supplierId,contexts.create(request,authentication)),request);}@PostMapping("/contacts")public ApiResponse<CommandResult> save(@Valid @RequestBody Contact body,HttpServletRequest request,Authentication authentication){return ok(service.saveContact(body.contactId(),body.supplierId(),body.contactName(),body.mobile(),body.email(),body.contactRole(),body.primary(),body.version(),contexts.create(request,authentication)),request);}@PostMapping("/users")public ApiResponse<CommandResult> bind(@Valid @RequestBody Bind body,HttpServletRequest request,Authentication authentication){return ok(service.bind(body.supplierId(),body.userId(),body.bindingRole(),body.primary(),contexts.create(request,authentication)),request);}@PostMapping("/users/{id}/unbind")public ApiResponse<CommandResult> unbind(@PathVariable long id,@Valid @RequestBody Version body,HttpServletRequest request,Authentication authentication){return ok(service.unbind(id,body.version(),contexts.create(request,authentication)),request);}private<T>ApiResponse<T>ok(T value,HttpServletRequest request){return ApiResponse.success(value,request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}public record Contact(Long contactId,@Positive long supplierId,@NotBlank String contactName,@NotBlank String mobile,String email,@NotBlank String contactRole,boolean primary,@PositiveOrZero int version){}public record Bind(@Positive long supplierId,@Positive long userId,@NotBlank String bindingRole,boolean primary){}public record Version(@PositiveOrZero int version){} }
